#include <stdio.h>

int main() {
  // Count 1 to 5
  for (int i = 1; i <= 5; i++) {
    printf("%d ", i);
  }
  printf("\n");
  // Nested for loop - multiplication table
  for (int row = 1; row <= 3; row++) {
    for (int col = 1; col <= 3; col++) {
      printf("%d ", row * col);
    }
    printf("\n");
  }
  return 0;
}
